#!/usr/bin/env python3
"""Generated by superpower-adapter."""

from __future__ import annotations

import argparse
import json
from pathlib import Path

from plan_context_common import (
    PHASE_FILES,
    context_dir_for_plan,
    current_plan_file,
    get_current_plan,
    load_jsonl,
    load_state,
    rel_posix,
    resolve_plan_path,
    validate_plan_location,
)
from spec_common import repo_root

EXIT_OK = 0
EXIT_BLOCK = 1
EXIT_WARN = 2
EXIT_USAGE = 64


def add_check(results: list[dict], name: str, status: str, message: str = '', next_steps: list[str] | None = None) -> None:
    results.append({
        'name': name,
        'status': status,
        'message': message,
        'nextSteps': next_steps or [],
    })


def aggregate_status(checks: list[dict]) -> str:
    statuses = [item['status'] for item in checks]
    if 'block' in statuses:
        return 'block'
    if 'warn' in statuses:
        return 'warn'
    return 'ok'


def exit_code_for_status(status: str) -> int:
    if status == 'block':
        return EXIT_BLOCK
    if status == 'warn':
        return EXIT_WARN
    return EXIT_OK


def render_text(result: dict) -> str:
    lines = [
        f"Phase: {result['phase']}",
        f"Status: {result['status'].upper()}",
        '',
        'Checks:',
    ]

    for item in result['checks']:
        lines.append(f"- [{item['status'].upper()}] {item['name']}")
        if item.get('message'):
            lines.append(f"  - {item['message']}")
        for step in item.get('nextSteps', []):
            lines.append(f"  - Next: {step}")

    if result.get('nextSteps'):
        lines.extend(['', 'Next steps:'])
        for step in result['nextSteps']:
            lines.append(f'- {step}')

    return '\n'.join(lines)


def render_json(result: dict) -> str:
    return json.dumps(result, ensure_ascii=False, indent=2)


def load_target_plan(root: Path, plan_arg: str | None, missing_current_plan_status: str = 'block') -> tuple[Path | None, list[dict]]:
    checks: list[dict] = []

    if plan_arg:
        try:
            plan_path = resolve_plan_path(root, plan_arg)
            validate_plan_location(root, plan_path)
        except ValueError as exc:
            add_check(checks, 'plan_resolved', 'block', str(exc))
            return None, checks

        if not plan_path.is_file():
            add_check(checks, 'plan_exists', 'block', f'Plan file not found: {rel_posix(root, plan_path)}')
            return None, checks

        add_check(checks, 'plan_resolved', 'ok', f'Resolved plan: {rel_posix(root, plan_path)}')
        return plan_path, checks

    plan_path = get_current_plan(root)
    if plan_path is None:
        pointer = current_plan_file(root)
        if pointer.is_file():
            add_check(checks, 'current_plan', 'block', 'Current plan pointer exists but does not resolve to a valid plan')
        else:
            add_check(checks, 'current_plan', missing_current_plan_status, 'No current plan set')
        return None, checks

    add_check(checks, 'current_plan', 'ok', f'Resolved current plan: {rel_posix(root, plan_path)}')
    return plan_path, checks


def check_sidecar_initialized(root: Path, plan_path: Path, strict: bool = False) -> dict:
    context_dir = context_dir_for_plan(plan_path)
    if not context_dir.is_dir():
        level = 'block' if strict else 'warn'
        return {
            'name': 'sidecar_initialized',
            'status': level,
            'message': f'Context sidecar not initialized: {rel_posix(root, context_dir)}',
            'nextSteps': [
                f'python3 superpowers/scripts/plan-context.py init {rel_posix(root, plan_path)} --set-current'
            ],
        }

    state_path = context_dir / 'state.json'
    if not state_path.is_file():
        return {
            'name': 'sidecar_state',
            'status': 'block',
            'message': f'Missing state.json: {rel_posix(root, state_path)}',
            'nextSteps': [],
        }

    return {
        'name': 'sidecar_initialized',
        'status': 'ok',
        'message': f'Context sidecar ready: {rel_posix(root, context_dir)}',
        'nextSteps': [],
    }


def check_plan_records(root: Path, plan_path: Path) -> dict:
    context_dir = context_dir_for_plan(plan_path)
    plan_jsonl = context_dir / PHASE_FILES['plan']

    if not plan_jsonl.is_file():
        return {
            'name': 'plan_records',
            'status': 'block',
            'message': f'Missing {plan_jsonl.name}',
            'nextSteps': [],
        }

    try:
        rows = load_jsonl(plan_jsonl)
    except ValueError as exc:
        return {
            'name': 'plan_records',
            'status': 'block',
            'message': str(exc),
            'nextSteps': [],
        }

    if not rows:
        return {
            'name': 'plan_records',
            'status': 'block',
            'message': 'plan.jsonl has no planning-selected spec records',
            'nextSteps': [
                'Read .superpowers/spec/index.md and select the minimum relevant specs',
                'Then add them with python3 superpowers/scripts/plan-context.py add --phase plan ...',
            ],
        }

    return {
        'name': 'plan_records',
        'status': 'ok',
        'message': f'Found {len(rows)} planning-selected records',
        'nextSteps': [],
    }


def check_phase_records(root: Path, plan_path: Path, phase: str, strict: bool) -> dict:
    context_dir = context_dir_for_plan(plan_path)
    phase_jsonl = context_dir / PHASE_FILES[phase]

    if not phase_jsonl.is_file():
        level = 'block' if strict else 'warn'
        return {
            'name': f'{phase}_records',
            'status': level,
            'message': f'Missing {phase_jsonl.name}',
            'nextSteps': [],
        }

    try:
        rows = load_jsonl(phase_jsonl)
    except ValueError as exc:
        return {
            'name': f'{phase}_records',
            'status': 'block',
            'message': str(exc),
            'nextSteps': [],
        }

    if not rows:
        level = 'block' if strict else 'warn'
        next_steps = []
        if phase != 'plan':
            next_steps = [
                f'Add phase-specific context with python3 superpowers/scripts/plan-context.py add --phase {phase} ...'
            ]
        return {
            'name': f'{phase}_records',
            'status': level,
            'message': f'{phase_jsonl.name} has no records yet',
            'nextSteps': next_steps,
        }

    return {
        'name': f'{phase}_records',
        'status': 'ok',
        'message': f'Found {len(rows)} {phase} records',
        'nextSteps': [],
    }


def check_sidecar_state(root: Path, plan_path: Path, expected_phase: str | None = None, strict: bool = False) -> dict:
    context_dir = context_dir_for_plan(plan_path)
    state = load_state(context_dir)
    if state is None:
        return {
            'name': 'sidecar_state',
            'status': 'block',
            'message': 'Missing or unreadable state.json',
            'nextSteps': [],
        }

    problems: list[str] = []

    if state.get('planPath') != rel_posix(root, plan_path):
        problems.append('state.json planPath does not match target plan')

    if state.get('contextDir') != rel_posix(root, context_dir):
        problems.append('state.json contextDir does not match sidecar directory')

    current_phase = state.get('currentPhase')
    if expected_phase and current_phase and current_phase != expected_phase:
        level = 'block' if strict else 'warn'
        return {
            'name': 'sidecar_phase',
            'status': level,
            'message': f'Current phase is {current_phase}, expected {expected_phase}',
            'nextSteps': [],
        }

    if problems:
        return {
            'name': 'sidecar_state',
            'status': 'block',
            'message': '; '.join(problems),
            'nextSteps': [],
        }

    return {
        'name': 'sidecar_state',
        'status': 'ok',
        'message': f"State is valid (currentPhase={current_phase or 'unknown'})",
        'nextSteps': [],
    }


def check_completion_inputs(args: argparse.Namespace) -> dict:
    if args.summary or args.changed_file:
        return {
            'name': 'completion_inputs',
            'status': 'ok',
            'message': 'Completion inputs provided',
            'nextSteps': [],
        }

    return {
        'name': 'completion_inputs',
        'status': 'warn',
        'message': 'No summary or changed files provided; durable knowledge check may be weak',
        'nextSteps': [],
    }


def check_update_spec_candidate(args: argparse.Namespace) -> dict:
    summary = (args.summary or '').strip().lower()
    joined_files = ' '.join(args.changed_file or []).lower()

    signals: list[str] = []

    keywords = [
        'contract',
        'payload',
        'error',
        'validation',
        'convention',
        'behavior',
        'api',
        'response',
        'request',
    ]
    for key in keywords:
        if key in summary:
            signals.append(f'summary mentions {key}')
            break

    interesting_paths = [
        'api',
        'handler',
        'backend',
        'frontend',
        'route',
        'controller',
        'schema',
    ]
    for key in interesting_paths:
        if key in joined_files:
            signals.append(f'changed files suggest implementation rule changes ({key})')
            break

    if not signals:
        return {
            'name': 'update_spec_candidate',
            'status': 'ok',
            'message': 'No strong durable-knowledge signal detected',
            'nextSteps': [],
        }

    return {
        'name': 'update_spec_candidate',
        'status': 'warn',
        'message': 'This task may have produced durable implementation knowledge',
        'nextSteps': [
            'Consider running python3 superpowers/scripts/spec_update_run.py ...'
        ],
    }


def build_result(phase: str, checks: list[dict]) -> dict:
    next_steps: list[str] = []
    for item in checks:
        next_steps.extend(item.get('nextSteps', []))

    return {
        'phase': phase,
        'status': aggregate_status(checks),
        'checks': checks,
        'nextSteps': next_steps,
    }


def emit_result(args: argparse.Namespace, result: dict) -> int:
    print(render_json(result) if args.json else render_text(result))
    return exit_code_for_status(result['status'])


def cmd_planning(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    checks: list[dict] = []

    plan_path, plan_checks = load_target_plan(root, args.plan)
    checks.extend(plan_checks)
    if plan_path is None:
        return emit_result(args, build_result('planning', checks))

    checks.append(check_sidecar_initialized(root, plan_path, strict=False))
    return emit_result(args, build_result('planning', checks))


def cmd_implement(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    checks: list[dict] = []

    plan_path, plan_checks = load_target_plan(root, args.plan)
    checks.extend(plan_checks)
    if plan_path is None:
        return emit_result(args, build_result('implement', checks))

    checks.append(check_sidecar_initialized(root, plan_path, strict=True))
    if aggregate_status(checks) == 'block':
        return emit_result(args, build_result('implement', checks))

    checks.append(check_sidecar_state(root, plan_path, expected_phase=None, strict=args.strict))
    checks.append(check_plan_records(root, plan_path))
    return emit_result(args, build_result('implement', checks))


def cmd_review(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    checks: list[dict] = []

    plan_path, plan_checks = load_target_plan(root, args.plan)
    checks.extend(plan_checks)
    if plan_path is None:
        return emit_result(args, build_result('review', checks))

    checks.append(check_sidecar_initialized(root, plan_path, strict=True))
    if aggregate_status(checks) == 'block':
        return emit_result(args, build_result('review', checks))

    checks.append(check_sidecar_state(root, plan_path, expected_phase=None, strict=args.strict))
    checks.append(check_plan_records(root, plan_path))
    checks.append(check_phase_records(root, plan_path, 'review', strict=False))
    return emit_result(args, build_result('review', checks))


def cmd_completion(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    checks: list[dict] = []

    plan_path, plan_checks = load_target_plan(root, args.plan, missing_current_plan_status='warn')
    checks.extend(plan_checks)

    if plan_path is not None:
        checks.append(check_sidecar_initialized(root, plan_path, strict=False))
        if aggregate_status(checks) != 'block':
            checks.append(check_sidecar_state(root, plan_path, expected_phase=None, strict=False))

    checks.append(check_completion_inputs(args))
    checks.append(check_update_spec_candidate(args))
    return emit_result(args, build_result('completion', checks))


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser()
    subparsers = parser.add_subparsers(dest='command', required=True)

    def add_common(subparser: argparse.ArgumentParser) -> None:
        subparser.add_argument('--plan')
        subparser.add_argument('--json', action='store_true')
        subparser.add_argument('--strict', action='store_true')

    planning_parser = subparsers.add_parser('planning')
    add_common(planning_parser)
    planning_parser.set_defaults(func=cmd_planning)

    implement_parser = subparsers.add_parser('implement')
    add_common(implement_parser)
    implement_parser.set_defaults(func=cmd_implement)

    review_parser = subparsers.add_parser('review')
    add_common(review_parser)
    review_parser.set_defaults(func=cmd_review)

    completion_parser = subparsers.add_parser('completion')
    add_common(completion_parser)
    completion_parser.add_argument('--summary')
    completion_parser.add_argument('--changed-file', action='append', default=[])
    completion_parser.set_defaults(func=cmd_completion)

    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()
    return args.func(args)


if __name__ == '__main__':
    raise SystemExit(main())
